class Solution:
    def largestValues(self, root: Optional[TreeNode]) -> List[int]:
        if not root: return []
        from collections import deque
        q = deque([root])
        ans = []
        while q:
            mx = float("-inf")
            for _ in range(len(q)):
                n = q.popleft()
                mx = max(mx, n.val)
                if n.left: q.append(n.left)
                if n.right: q.append(n.right)
            ans.append(mx)
        return ans

