class Solution {
public:
    vector<int> largestValues(TreeNode* root) {
        if (!root) return {};
        queue<TreeNode*> q;
        q.push(root);
        vector<int> ans;
        while (!q.empty()) {
            int sz = q.size(), mx = INT_MIN;
            while (sz--) {
                auto* n = q.front(); q.pop();
                mx = max(mx, n->val);
                if (n->left) q.push(n->left);
                if (n->right) q.push(n->right);
            }
            ans.push_back(mx);
        }
        return ans;
    }
};
